    black_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                black_cells.append((i, j))

    # Sort black cells by their row and then by their column
    black_cells.sort()

    # Try to find the top-left and bottom-right corners of the rectangle
    top_left = None
    bottom_right = None
    for i in range(len(black_cells)):
        for j in range(i + 1, len(black_cells)):
            if black_cells[i][0] == black_cells[j][0] or black_cells[i][1] == black_cells[j][1]:
                top_left = black_cells[i] if black_cells[i][0] < black_cells[j][0] or black_cells[i][1] < black_cells[j][1] else black_cells[j]
                bottom_right = black_cells[i] if black_cells[i][0] > black_cells[j][0] or black_cells[i][1] > black_cells[j][1] else black_cells[j]
                break
        if bottom_right is not None:
            break

    # Check if we have found a valid rectangle
    if top_left is not None and bottom_right is not None:
