def count_possible_xor_values(N, A):
    # Generate all possible xor values
    possible_values = set([0])
    for i in range(1, N + 1):
        possible_values |= {x ^ A[i-1] for x in possible_values}
        possible_values |= {x ^ A[i-1] ^ A[j-1] for x in possible_values for j in range(i + 1, N + 1)}
        possible_values |= {x ^ A[i-1] ^ A[j-1] ^ A[k-1] for x in possible_values for j in range(i + 1, N + 1) for k in range(j + 1, N + 1)}
        # Continue this pattern up to N+1 elements
    return len(possible_values)

