from collections import defaultdict

def simulate_blocks(N, W, blocks, Q, queries):
    # Initialize the grid and simulate the movement of blocks
    grid = defaultdict(set)
    for x, y in blocks:
        grid[y].add(x)

    results = []
    for T, A in queries:
        current_time = T
        while current_time < T + 0.5:
            # Remove blocks from the bottom row if the entire bottom row is filled
            while grid[1]:
                block = min(grid[1])
                grid[1].remove(block)
                if block in grid[2]:
                    grid[2].remove(block)

            # Move blocks one cell downward if possible
            for y in range(2, 10**9 + 1):
                if y in grid:
                    for x in grid[y]:
                        if y + 1 not in grid or x not in grid[y + 1]:
                            grid[y + 1].add(x)
                            grid[y].remove(x)

            current_time += 1

        # Check if block A exists at time T + 0.5
        if A in grid[T + 1]:
            results.append("Yes")
        else:
            results.append("No")

    return results

